package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.BedragVerdelerFactory;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.util.Collection;

@AllArgsConstructor
public class BerekenPatronaleVerminderingOnthaalOuders {

    private static final LocalDate START_PATRONALE_VERMINDERING_ONTHAALOUDERS = new LocalDate(2022, 1, 1);

    private final PersoonsDataManager dataManager;
    private final LoonElementManager elementManager;
    private final RekenTijd rekenTijd;

    public void bereken(Opdracht opdracht) {
        if (isActief() && opdracht.getHoedanigheid() == Hoedanigheid.ONTHAALOUDERS) {
            Money vermindering = dataManager.getOnthaalOudersPatronaleVermindering(opdracht);
            Collection<LoonElement> elementen = elementManager.getOpdrachtsElementen(opdracht);
            Money totalePatronaleBijdrage = elementen.stream().map(this::getPatronaleBijdrage).reduce(Money.ZERO, Money::add);
            vermindering = vermindering.min(totalePatronaleBijdrage);
            BedragVerdelerFactory.verdeelBedragVolgensBasisPut(RekenPatronaalRszKey.VERMINDERING_PATRONALE_BIJDRAGE_ONTHAAL_OUDERS_KEY, vermindering,
                    RekenPatronaalRszKey.PATRONALE_BIJDRAGE_RSZ_KEY, totalePatronaleBijdrage, elementen);
        }

    }

    private Money getPatronaleBijdrage(LoonElement element) {
        return element.getPropertyMoney(RekenPatronaalRszKey.PATRONALE_BIJDRAGE_RSZ_KEY);
    }

    private boolean isActief() {
        return !rekenTijd.beginDatum.isBefore(START_PATRONALE_VERMINDERING_ONTHAALOUDERS);
    }
}
